#!/usr/bin/env bash
set -euo pipefail;source "$(dirname "$0")/lib/android-test.sh";serial=emulator-5554;package=org.archphene.linux.p28ae847c2c818246c42d2ba69544759e;probe=;timeout=30;while (($#));do case "$1" in --serial)serial="${2:?}";shift 2;;--package)package="${2:?}";shift 2;;--probe-path)probe="${2:?}";shift 2;;--timeout-seconds)timeout="${2:?}";shift 2;;*)archphene_die "unknown argument: $1";;esac;done;archphene_test_init "$serial";activity="$(archphene_launcher "$package")";archphene_adb_run logcat -c;archphene_adb_run shell am start -W -n "$activity" >/dev/null;log="$(archphene_wait_log 'Private D-Bus|desktop bridge' "$timeout" 'ArchpheneDesktop:I AndroidRuntime:E *:S')";[[ "$log" != *'FATAL EXCEPTION'* ]] || archphene_die 'print wrapper crashed';dump="$(archphene_adb_run shell dumpsys package "$package")";[[ "$dump" == *android.permission.INTERNET* ]] || archphene_die 'wrapper package contract unavailable';archphene_note "Android XDG printing passed on $serial: private D-Bus startup and print portal contract verified."
